impl Solution { pub fn beautiful_splits(nums: Vec<i32>) -> i32 { let n = nums.len(); let mut lcp = vec![vec![0; n + 1]; n + 1]; for i in (0..n).rev() { for j in (0..n).rev() { if nums[i] == nums[j] { lcp[i][j] = lcp[i+1][j+1] + 1; } } } let mut black_count = 0; for i in 1..n-1 { for j in i+1..n { let (len1, len2, len3) = (i, j - i, n - j); if (len2 >= len1 && lcp[0][i] >= len1) || (len3 >= len2 && lcp[i][j] >= len2) { black_count += 1; } } } black_count } }